INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "お！\nあそこに困ってそうな人発見！", 1.4, 0, 0, 2, 1001, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1, 1, "春咲 ひより", 0, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "大切な人を\n守れるようになりたい…って", 1.4, 0, 0, 2, 1002, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1, 1, "草野 優衣", 0, 0, "みんなみたいに\nわたしも強くならなきゃ", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "キミに必要な集中力と感性が", 1.4, 0, 0, 2, 1003, "少しは磨かれると思いますよ。", 1, 1, "士条 怜", 0, 0, "フェンシングを始めてみては？", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "今日はなにして遊ぶ？", 1.5, 0, 0, 2, 1004, "みそぎはねぇ、\nかくれんぼやりたい！", 1, 1, "穂高 みそぎ", 0, 0, "ねぇ、にいちゃん！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "ねぇ…", 1.4, 0, 0, 2, 1006, "私といっしょに…\nいかない？", 1, 1, "風宮 あかり", 0, 0, "風宮あかりです", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "プリンたべたいのー", 1.5, 0, 0, 2, 1007, "食べ物の恨みは怖いのー", 1, 1, "出雲 宮子", 0, 0, "出雲宮子なのー", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "キミもボクの美貌に\n吸い寄せられたんだね。", 1.4, 0, 0, 2, 1008, "いいよ。\n見られることは運命さ…", 1, 1, "虹村 雪", 0, 0, "ボクは虹村雪。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1.4, 0, 0, 2, 1009, "人呼んで「疾風の冥姫」!!", 1, 1, "柊杏奈", 0, 0, "フッ…聞いて後悔するがいい！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1.5, 0, 0, 2, 1010, "ほんまおおきにやわ～♪", 1, 1, "姫宮 真歩", 0, 0, "マホマホ王国のプリンセス、\nまほ姫どす", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "生き別れたお兄ちゃんを探して\n三千世界！", 1.4, 0, 0, 2, 1011, "ここで会ったが\n100年目～！", 1, 1, "衣之咲 璃乃", 0, 0, "衣之咲璃乃です！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "ち、超能力って…\n何のことかな～？", 1.4, 0, 0, 2, 1012, "…って、お願い！\n誰にも言わないでおいて～！", 1, 1, "柏崎 初音", 0, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "一応カリスマ読モJKやってまっす！", 1.4, 0, 0, 2, 1016, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1, 1, "美波 鈴奈", 0, 0, "ちょす！\n美波鈴奈だよ～♪", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "東京は遊園地みたいなところさー", 1.4, 0, 0, 2, 1017, "でも、沖縄もとってもいいとこさー", 1, 1, "喜屋武 香織", 0, 0, "はいたーい。\n喜屋武香織さー。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "先生って呼ばれるのは\nくすぐったいから", 1.4, 0, 0, 2, 1018, "イオちゃんって呼んでね。", 1, 1, "支倉 伊緒", 0, 0, "支倉伊緒です。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "あ！/\お兄ちゃ～ん\nまってよ～", 1.5, 0, 0, 2, 1020, "ミミをおいてかないでぇ～", 1, 1, "茜 ミミ", 0, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "あの……\nふぇ……", 1.5, 0, 0, 2, 1021, "ふぇぇぇぇぇん……", 1, 1, "栗林 くるみ", 0, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "こんな私に貴重な時間を\n割いていただき、", 1.4, 0, 0, 2, 1022, "なんてありがとうございます！", 1, 1, "風宮 より", 0, 0, "風宮よりです。\nあああああ！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "おにいちゃんどこいくの？\nえ？", 1.5, 0, 0, 2, 1023, "私こっち行きたいー\nね、早く早くー", 1, 1, "北条 綾音", 0, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "ふ、不束者ですが\nどうぞ末永く…って、", 1.4, 0, 0, 2, 1025, "これて何か違う…\nあああすみません！", 1, 1, "天野 すずめ", 0, 0, "わっ…わっ…私、\n天野すずめといいます！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "あなたは…運命の……\n伴侶……", 1.4, 0, 0, 2, 1027, "離しませんわ………\n絶対に…!!", 1, 1, "倉石 恵理子", 0, 0, "……クスクス…私は\n…倉石恵理子……", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1.4, 0, 0, 2, 1028, "…そうでしょ？？", 1, 1, "佐々木 咲恋", 0, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "ぇっと…\nキミ、私のこと知らないの?!", 1.4, 0, 0, 2, 1029, "あはは、\n私もまだまだだなぁ～", 1, 1, "桜井 望", 0, 0, "桜井望だよ！\nよろしくねっ", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "初めまして、\n私はニノン・ジュベール申すデス！", 1.4, 0, 0, 2, 1030, "ショーグン、\nワタシと一緒に天下統一デース！", 1, 1, "ニノン・ジュベール", 0, 0, "デケデケデンっ！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "でもって私の隣にいるのが……\nえ、見えない？", 1.4, 0, 0, 2, 1031, "おかしいですね……", 1, 1, "上喜 しのぶ", 0, 0, "上喜しのぶです。\n手元のドクロが父です。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "けんども\nそれには足りないモンが…", 1.5, 0, 0, 2, 1033, "そう、\nオラのボケに突っ込める相方が…！", 1, 1, "野戸まひる", 0, 0, "目指すはビッグな\nお笑い芸人だっぺ！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "ちょっと緊張しちゃって…", 1.4, 0, 0, 2, 1034, "ちょ\nちょっと一杯飲んできます…！", 1, 1, "綾瀬 ゆかり", 0, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "知らない人とは話しちゃいけないので", 1.5, 0, 0, 2, 1036, "これ以上お話しすることは…\nないです！", 1, 1, "氷川 鏡華", 0, 0, "氷川鏡華…です", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "……あ、アラーム。", 1.4, 0, 0, 2, 1038, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1, 1, "柏崎 栞", 0, 0, "柏崎…栞です。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "私、一人も友達がいなくて……", 1.4, 0, 0, 2, 1040, "野に咲く花が、\n唯一の話相手です。", 1, 1, "双葉 碧", 0, 0, "ふ、双葉碧です。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1.4, 0, 0, 2, 1042, "そう思っています。", 1, 1, "三角 千歌", 0, 0, "三角千歌です。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "あぁ？\nお前のそいつの仲間か？", 1.4, 0, 0, 2, 1043, "う、疑ってすまなかったな…", 1, 1, "安芸 真琴", 0, 0, "安芸真琴だ。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "生けとし生ける全ての者よ！", 1.4, 0, 0, 2, 1044, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1, 1, "イリヤ・オーンスタイン", 0, 0, "わらわこそは夜を総べる者！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "ぐふふふふ……はっ！", 1.4, 0, 0, 2, 1045, "ｌク、クウカに何かご用ですか!?", 1, 1, "遠見 空花", 0, 0, "そこで騎士は妖精を乱暴に……", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1.4, 0, 0, 2, 1046, "う～ん…\n猫ってホントに最高にゃ～♪", 1, 1, "宮坂たまき", 0, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "それでは早速クエストに…", 1.4, 0, 0, 2, 1048, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1, 1, "大神 美冬", 0, 0, "大神美冬よ！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "クエストもバトルも\n掃除も洗濯も", 1.4, 0, 0, 2, 1049, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1, 1, "星野静流", 0, 0, "星野静流だよ！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "見ての通りの\nセクシー美少女で", 1.5, 0, 0, 2, 1050, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1, 1, "玉泉美咲", 0, 0, "アタシは玉泉美咲。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "？？？？", 1.4, 0, 0, 2, 1052, "？？？？", 1, 1, "リマ", 0, 0, "？？？", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 0, 2, 1053, "そ、そこまでいうなら\nもらってやる", 1, 1, "モニカ・ヴァイスヴィント", 0, 0, "モニカ・ヴァイスヴィントだ。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 0, 2, 1058, "そ、そこまでいうなら\nもらってやる", 1, 1, "ペコリーヌ", 0, 0, "モニカ・ヴァイスヴィントだ。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 0, 2, 1059, "そ、そこまでいうなら\nもらってやる", 1, 1, "コッコロ", 0, 0, "モニカ・ヴァイスヴィントだ。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, "菓子でつろうなどと\n稚拙な策を……", 1.5, 0, 0, 2, 1060, "そ、そこまでいうなら\nもらってやる", 1, 1, "キャル", 0, 0, "モニカ・ヴァイスヴィントだ。", 0);
